import React from 'react';
import Trade from './Trade';

const trades = [
    {id:1, stock:'MES', method:'Bollinger', quantity:1, profitLoss:1},
    {id:2, stock:'MES', method:'S&R', quantity:2, profitLoss:3}
]

function TradeList() {
    return(
        <div>
            <table>
                <th>
                    <tr>
                        <td>Id</td>
                        <td>Stock</td>
                        <td>Method</td>
                        <td>Quantity</td>
                        <td>Profit/Loss</td>
                    </tr>
                </th>
                <tr>
                    { trades.map(trade => {
                        return <Trade trade={trade}/>
                    }) }
                </tr>
                
            </table>
            
        </div>
    )
}

export default TradeList;
